class Solution:
    def largestAltitude(self, gain):
        alts = [0]
        for g in gain:
            alts.append(alts[-1] + g)
        return max(alts)

solutions.python:
class Solution:
    def largestAltitude(self, gain):
        best = 0
        cur = 0
        for g in gain:
            cur += g
            if cur > best:
                best = cur
        return best

